import jwt
import json
from datetime import datetime
from typing import Dict, Any, Optional, List

def decode_and_verify_jwt(
    token: str,
    secret_key: str,
    algorithms: Optional[List[str]] = None,
    verify_signature: bool = True,
    verify_exp: bool = True,
    verify_nbf: bool = True,
    verify_iat: bool = True,
    audience: Optional[str] = None,
    issuer: Optional[str] = None,
    required_claims: Optional[List[str]] = None
) -> Dict[str, Any]:
    """
    Decode and verify a JWT token with security best practices.
    
    Args:
        token: The JWT token string to decode
        secret_key: The secret key or public key for verification
        algorithms: List of allowed algorithms (e.g., ['HS256', 'RS256'])
        verify_signature: Whether to verify the token signature
        verify_exp: Whether to verify expiration time
        verify_nbf: Whether to verify not-before time
        verify_iat: Whether to verify issued-at time
        audience: Expected audience claim
        issuer: Expected issuer claim
        required_claims: List of required claim names
        
    Returns:
        Dictionary containing decoded token payload and metadata
    """
    if algorithms is None:
        algorithms = ['HS256', 'HS384', 'HS512', 'RS256', 'RS384', 'RS512']
    
    result = {
        'valid': False,
        'payload': None,
        'header': None,
        'errors': [],
        'warnings': [],
        'metadata': {}
    }
    
    try:
        # Decode header without verification first for inspection
        unverified_header = jwt.get_unverified_header(token)
        result['header'] = unverified_header
        
        # Check if algorithm is in allowlist
        token_algorithm = unverified_header.get('alg')
        if token_algorithm not in algorithms:
            result['errors'].append(
                f"Algorithm '{token_algorithm}' not in allowlist: {algorithms}"
            )
            result['warnings'].append("Token algorithm not allowed - potential security risk")
        
        # Decode without verification for inspection
        unverified_payload = jwt.decode(
            token,
            options={
                'verify_signature': False,
                'verify_exp': False,
                'verify_nbf': False,
                'verify_iat': False
            }
        )
        result['payload'] = unverified_payload
        
        # Check for standard claims
        standard_claims = ['exp', 'nbf', 'iat', 'iss', 'aud', 'sub']
        present_claims = [claim for claim in standard_claims if claim in unverified_payload]
        result['metadata']['present_claims'] = present_claims
        
        # Check expiration
        if 'exp' in unverified_payload:
            exp_timestamp = unverified_payload['exp']
            exp_datetime = datetime.fromtimestamp(exp_timestamp)
            result['metadata']['expiration'] = exp_datetime.isoformat()
            result['metadata']['expired'] = datetime.utcnow() > exp_datetime
            if result['metadata']['expired']:
                result['warnings'].append(f"Token expired at {exp_datetime.isoformat()}")
        else:
            result['warnings'].append("No expiration claim (exp) found - token never expires")
        
        # Check issued at
        if 'iat' in unverified_payload:
            iat_timestamp = unverified_payload['iat']
            iat_datetime = datetime.fromtimestamp(iat_timestamp)
            result['metadata']['issued_at'] = iat_datetime.isoformat()
        
        # Check not before
        if 'nbf' in unverified_payload:
            nbf_timestamp = unverified_payload['nbf']
            nbf_datetime = datetime.fromtimestamp(nbf_timestamp)
            result['metadata']['not_before'] = nbf_datetime.isoformat()
            result['metadata']['not_yet_valid'] = datetime.utcnow() < nbf_datetime
        
        # Now verify with signature if requested
        if verify_signature:
            decode_options = {
                'verify_signature': True,
                'verify_exp': verify_exp,
                'verify_nbf': verify_nbf,
                'verify_iat': verify_iat,
                'require': required_claims or []
            }
            
            decode_kwargs = {
                'jwt': token,
                'key': secret_key,
                'algorithms': algorithms,
                'options': decode_options
            }
            
            if audience:
                decode_kwargs['audience'] = audience
            if issuer:
                decode_kwargs['issuer'] = issuer
            
            verified_payload = jwt.decode(**decode_kwargs)
            result['valid'] = True
            result['payload'] = verified_payload
            result['metadata']['signature_verified'] = True
            
        else:
            result['warnings'].append("Signature verification disabled - for debugging only")
            result['metadata']['signature_verified'] = False
        
        # Check for required claims
        if required_claims:
            missing_claims = [claim for claim in required_claims if claim not in unverified_payload]
            if missing_claims:
                result['errors'].append(f"Missing required claims: {missing_claims}")
            else:
                result['metadata']['all_required_claims_present'] = True
        
    except jwt.ExpiredSignatureError as e:
        result['errors'].append(f"Token expired: {str(e)}")
    except jwt.InvalidSignatureError as e:
        result['errors'].append(f"Invalid signature: {str(e)}")
    except jwt.InvalidAlgorithmError as e:
        result['errors'].append(f"Invalid algorithm: {str(e)}")
    except jwt.InvalidTokenError as e:
        result['errors'].append(f"Invalid token: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def print_jwt_debug_info(token: str, secret_key: str, algorithms: Optional[List[str]] = None):
    """
    Print formatted debug information about a JWT token.
    
    Args:
        token: The JWT token string
        secret_key: The secret key for verification
        algorithms: List of allowed algorithms
    """
    result = decode_and_verify_jwt(token, secret_key, algorithms)
    
    print("=" * 80)
    print("JWT TOKEN DEBUG INFORMATION")
    print("=" * 80)
    
    print("\n[HEADER]")
    print(json.dumps(result['header'], indent=2))
    
    print("\n[PAYLOAD]")
    print(json.dumps(result['payload'], indent=2))
    
    print("\n[VALIDATION STATUS]")
    print(f"Valid: {result['valid']}")
    print(f"Signature Verified: {result['metadata'].get('signature_verified', False)}")
    
    if result['metadata'].get('expired'):
        print(f"⚠️  EXPIRED at {result['metadata']['expiration']}")
    elif 'expiration' in result['metadata']:
        print(f"✓ Expires at {result['metadata']['expiration']}")
    
    if 'issued_at' in result['metadata']:
        print(f"Issued at: {result['metadata']['issued_at']}")
    
    if result['warnings']:
        print("\n[WARNINGS]")
        for warning in result['warnings']:
            print(f"⚠️  {warning}")
    
    if result['errors']:
        print("\n[ERRORS]")
        for error in result['errors']:
            print(f"❌ {error}")
    
    print("\n" + "=" * 80)


